import { useEffect, useState } from "react";
import { PageShell } from "@/components/orderly/PageShell";
import { OdsCheckbox } from "@/components/orderly/OdsCheckbox";
import { Globe, FlaskConical, Layers, Puzzle, Star } from "lucide-react";
import { useTranslation } from "@/i18n";
import { storageKey } from "@/utils/storage";

interface Chain {
  id: number;
  name: string;
  symbol: string;
  type: "L1" | "L2";
  network: "mainnet" | "testnet";
}

const supportedChains: Chain[] = [
  { id: 1, name: "Ethereum", symbol: "ETH", type: "L1", network: "mainnet" },
  { id: 56, name: "BNB Chain", symbol: "BNB", type: "L1", network: "mainnet" },
  {
    id: 900900900,
    name: "Solana",
    symbol: "SOL",
    type: "L1",
    network: "mainnet",
  },
  { id: 143, name: "Monad", symbol: "MON", type: "L1", network: "mainnet" },
  { id: 1329, name: "Sei", symbol: "SEI", type: "L1", network: "mainnet" },
  {
    id: 43114,
    name: "Avalanche",
    symbol: "AVAX",
    type: "L1",
    network: "mainnet",
  },
  { id: 146, name: "Sonic", symbol: "S", type: "L1", network: "mainnet" },
  {
    id: 80094,
    name: "Berachain",
    symbol: "BERA",
    type: "L1",
    network: "mainnet",
  },
  { id: 1514, name: "Story", symbol: "IP", type: "L1", network: "mainnet" },
  {
    id: 42161,
    name: "Arbitrum One",
    symbol: "ETH",
    type: "L2",
    network: "mainnet",
  },
  { id: 10, name: "Optimism", symbol: "ETH", type: "L2", network: "mainnet" },
  { id: 8453, name: "Base", symbol: "ETH", type: "L2", network: "mainnet" },
  { id: 5000, name: "Mantle", symbol: "MNT", type: "L2", network: "mainnet" },
  { id: 2818, name: "Morph", symbol: "ETH", type: "L2", network: "mainnet" },
  { id: 34443, name: "Mode", symbol: "ETH", type: "L2", network: "mainnet" },
  { id: 98866, name: "Plume", symbol: "ETH", type: "L2", network: "mainnet" },
  { id: 2741, name: "Abstract", symbol: "ETH", type: "L2", network: "mainnet" },
  {
    id: 97,
    name: "BSC Testnet",
    symbol: "BNB",
    type: "L1",
    network: "testnet",
  },
  {
    id: 901901901,
    name: "Solana Devnet",
    symbol: "SOL",
    type: "L1",
    network: "testnet",
  },
  {
    id: 421614,
    name: "Arbitrum Sepolia",
    symbol: "ETH",
    type: "L2",
    network: "testnet",
  },
  {
    id: 10143,
    name: "Monad Testnet",
    symbol: "MON",
    type: "L2",
    network: "testnet",
  },
  {
    id: 11124,
    name: "Abstract Testnet",
    symbol: "ETH",
    type: "L2",
    network: "testnet",
  },
];

export default function BlockchainConfigPage() {
  const { t } = useTranslation();
  const [chainIds, setChainIds] = useState<number[]>([]);
  const [defaultChain, setDefaultChain] = useState<number | undefined>(
    undefined
  );
  const [disableMainnet, setDisableMainnet] = useState(false);
  const [disableTestnet, setDisableTestnet] = useState(false);
  const [toast, setToast] = useState<string | null>(null);

  useEffect(() => {
    const storedIds = localStorage.getItem(storageKey("orderlyChainIds"));
    if (storedIds) {
      try {
        setChainIds(JSON.parse(storedIds) as number[]);
      } catch {}
    }
    const storedDefault = localStorage.getItem(
      storageKey("orderlyDefaultChain")
    );
    if (storedDefault) {
      try {
        setDefaultChain(parseInt(storedDefault, 10));
      } catch {}
    }
  }, []);

  useEffect(() => {
    if (disableMainnet) {
      const mainnetChainIds = supportedChains
        .filter(chain => chain.network === "mainnet")
        .map(chain => chain.id);
      const filtered = chainIds.filter(id => !mainnetChainIds.includes(id));
      if (filtered.length !== chainIds.length) {
        setChainIds(filtered);
      }
    }
  }, [disableMainnet]);

  useEffect(() => {
    if (disableTestnet) {
      const testnetChainIds = supportedChains
        .filter(chain => chain.network === "testnet")
        .map(chain => chain.id);
      const filtered = chainIds.filter(id => !testnetChainIds.includes(id));
      if (filtered.length !== chainIds.length) {
        setChainIds(filtered);
      }
    }
  }, [disableTestnet]);

  useEffect(() => {
    localStorage.setItem(
      storageKey("orderlyChainIds"),
      JSON.stringify(chainIds)
    );
  }, [chainIds]);

  useEffect(() => {
    if (defaultChain !== undefined) {
      localStorage.setItem(
        storageKey("orderlyDefaultChain"),
        String(defaultChain)
      );
    } else {
      localStorage.removeItem(storageKey("orderlyDefaultChain"));
    }
  }, [defaultChain]);

  function showToast(message: string) {
    setToast(message);
    setTimeout(() => setToast(null), 3000);
  }

  function handleChainToggle(chainId: number) {
    if (chainIds.includes(chainId)) {
      const next = chainIds.filter(id => id !== chainId);
      setChainIds(next);
      if (defaultChain === chainId) {
        setDefaultChain(undefined);
      }
    } else {
      setChainIds([...chainIds, chainId]);
    }
  }

  function handleSelectAll() {
    const active = supportedChains.filter(chain => {
      if (disableMainnet && chain.network === "mainnet") return false;
      if (disableTestnet && chain.network === "testnet") return false;
      return true;
    });
    setChainIds(active.map(c => c.id));
    showToast(t("blockchainConfig.toast.allChainsSelected"));
  }

  function handleClearAll() {
    setChainIds([]);
    setDefaultChain(undefined);
    showToast(t("blockchainConfig.toast.allChainsCleared"));
  }

  function handleMainnetToggle(checked: boolean) {
    if (checked && disableTestnet) return;
    setDisableMainnet(checked);
    if (checked) {
      const mainnetChainIds = supportedChains
        .filter(chain => chain.network === "mainnet")
        .map(chain => chain.id);
      const filtered = chainIds.filter(id => !mainnetChainIds.includes(id));
      setChainIds(filtered);
      if (defaultChain && mainnetChainIds.includes(defaultChain)) {
        setDefaultChain(undefined);
      }
    }
  }

  function handleTestnetToggle(checked: boolean) {
    if (checked && disableMainnet) return;
    setDisableTestnet(checked);
    if (checked) {
      const testnetChainIds = supportedChains
        .filter(chain => chain.network === "testnet")
        .map(chain => chain.id);
      const filtered = chainIds.filter(id => !testnetChainIds.includes(id));
      setChainIds(filtered);
    }
  }

  const mainnetL1 = supportedChains.filter(
    c => c.network === "mainnet" && c.type === "L1"
  );
  const mainnetL2 = supportedChains.filter(
    c => c.network === "mainnet" && c.type === "L2"
  );
  const testnetL1 = supportedChains.filter(
    c => c.network === "testnet" && c.type === "L1"
  );
  const testnetL2 = supportedChains.filter(
    c => c.network === "testnet" && c.type === "L2"
  );

  const bothNetworksDisabled = disableMainnet && disableTestnet;

  const defaultChainOptions = (
    chainIds.length > 0 ? chainIds : supportedChains.map(c => c.id)
  ).filter(id => {
    const chain = supportedChains.find(c => c.id === id);
    if (!chain) return false;
    if (chain.network !== "mainnet") return false;
    if (disableMainnet) return false;
    return true;
  });

  function ChainCheckbox({ chain }: { chain: Chain }) {
    const isDefault = defaultChain === chain.id;
    const selected = chainIds.includes(chain.id);
    return (
      <label
        className={`flex cursor-pointer items-center rounded-lg border p-3 transition-all duration-200 ${
          isDefault
            ? "border-(--line-brand) bg-[rgba(188,135,255,0.08)] hover:bg-[rgba(188,135,255,0.12)]"
            : selected
              ? "border-(--line-brand) bg-[rgba(188,135,255,0.08)] hover:bg-[rgba(188,135,255,0.12)]"
              : "border-(--line-subtle) bg-(--bg-surface-secondary) hover:bg-(--bg-hover)"
        }`}
      >
        <OdsCheckbox
          checked={selected}
          onCheckedChange={() => handleChainToggle(chain.id)}
          className="mr-3"
        />
        <div className="flex flex-1 items-center">
          <div className="flex-1">
            <div className="flex items-center gap-2 text-sm font-medium text-(--fg-primary)">
              {chain.name}
              <span
                className={`rounded px-1.5 py-0.5 text-xs ${
                  chain.type === "L1"
                    ? "bg-blue-500/20 text-blue-300"
                    : "bg-green-500/20 text-green-300"
                }`}
              >
                {chain.type}
              </span>
              {chain.network === "testnet" && (
                <span className="rounded bg-orange-500/20 px-1.5 py-0.5 text-xs text-orange-300">
                  {t("blockchainConfig.testnet")}
                </span>
              )}
              {isDefault && (
                <span className="flex items-center gap-1 rounded bg-[rgba(188,135,255,0.2)] px-1.5 py-0.5 text-xs text-(--fg-brand)">
                  <Star className="h-3 w-3" />
                  {t("blockchainConfig.default")}
                </span>
              )}
            </div>
            <div className="text-xs text-(--fg-secondary)">
              {t("blockchainConfig.chainId")}: {chain.id} • {chain.symbol}
            </div>
          </div>
        </div>
      </label>
    );
  }

  return (
    <PageShell pageTitle={t("blockchainConfig.title")}>
      <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
        <div className="mb-6 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <p className="text-xs text-(--fg-secondary)">
              {t("blockchainConfig.selectChainsDescription")}
            </p>
          </div>
          <div className="flex gap-2">
            <button
              type="button"
              onClick={handleSelectAll}
              className="rounded-full px-3 py-1 text-xs font-medium text-(--fg-brand) transition-all hover:bg-[rgba(188,135,255,0.12)]"
              style={{ background: "rgba(188,135,255,0.08)" }}
            >
              {t("blockchainConfig.selectAll")}
            </button>
            <button
              type="button"
              onClick={handleClearAll}
              className="rounded-full bg-(--bg-hover) px-3 py-1 text-xs font-medium text-(--fg-secondary) transition-all hover:bg-[rgba(255,255,255,0.1)]"
            >
              {t("blockchainConfig.clearAll")}
            </button>
          </div>
        </div>

        {chainIds.length === 0 && (
          <div className="mb-6 rounded-lg border border-blue-500/20 bg-blue-500/10 px-4 py-3 text-center text-sm">
            <div className="mb-1 font-medium text-blue-300">
              {t("blockchainConfig.allChainsMode")}
            </div>
            <div className="text-xs leading-relaxed text-(--fg-secondary)">
              {t("blockchainConfig.allChainsDescription")}
            </div>
          </div>
        )}

        <div className="mb-6 space-y-3">
          <div>
            <label
              htmlFor="defaultChain"
              className="mb-1 block text-sm font-medium text-(--fg-primary)"
            >
              {t("blockchainConfig.defaultChain")}
            </label>
            <p className="mb-2 text-xs text-(--fg-secondary)">
              {t("blockchainConfig.defaultChainDescription")}
            </p>
          </div>
          <select
            id="defaultChain"
            value={defaultChain || ""}
            onChange={e =>
              setDefaultChain(
                e.target.value ? parseInt(e.target.value, 10) : undefined
              )
            }
            className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-base sm:text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
          >
            <option value="">{t("blockchainConfig.noDefaultChain")}</option>
            {defaultChainOptions.map(id => {
              const chain = supportedChains.find(c => c.id === id);
              return chain ? (
                <option key={chain.id} value={chain.id}>
                  {chain.name}
                </option>
              ) : null;
            })}
          </select>
          {defaultChain && (
            <div className="text-xs text-(--fg-secondary)">
              {t("blockchainConfig.selectedDefault")}:{" "}
              <span className="text-(--fg-brand)">
                {supportedChains.find(c => c.id === defaultChain)?.name ||
                  `${t("blockchainConfig.chainId")} ${defaultChain}`}
              </span>
            </div>
          )}
        </div>

        <div className="mb-6 flex gap-4">
          <label
            className={`flex cursor-pointer items-center transition-all ${
              disableTestnet ? "opacity-50" : "hover:text-(--fg-primary)"
            }`}
          >
            <OdsCheckbox
              checked={disableMainnet}
              disabled={disableTestnet}
              onCheckedChange={checked => handleMainnetToggle(checked === true)}
              className="mr-2"
            />
            <span className="text-sm text-(--fg-secondary)">
              {t("blockchainConfig.disableMainnet")}
            </span>
          </label>
          <label
            className={`flex cursor-pointer items-center transition-all ${
              disableMainnet ? "opacity-50" : "hover:text-(--fg-primary)"
            }`}
          >
            <OdsCheckbox
              checked={disableTestnet}
              disabled={disableMainnet}
              onCheckedChange={checked => handleTestnetToggle(checked === true)}
              className="mr-2"
            />
            <span className="text-sm text-(--fg-secondary)">
              {t("blockchainConfig.disableTestnet")}
            </span>
          </label>
        </div>

        {bothNetworksDisabled && (
          <div className="mb-6 rounded-lg border border-red-500/20 bg-red-500/10 px-4 py-3 text-center text-sm">
            <div className="mb-1 font-medium text-red-300">
              {t("blockchainConfig.invalidConfiguration")}
            </div>
            <div className="text-xs text-(--fg-secondary)">
              {t("blockchainConfig.cannotDisableBoth")}
            </div>
          </div>
        )}

        <div
          className={`mb-6 space-y-4 transition-all duration-300 ${
            disableMainnet ? "pointer-events-none opacity-50" : ""
          }`}
        >
          <h4 className="flex items-center text-sm font-semibold text-(--fg-primary)">
            <Globe className="mr-2 h-4 w-4" />
            {t("blockchainConfig.mainnetNetworks")}
            {disableMainnet && (
              <span className="ml-2 rounded bg-red-500/20 px-2 py-0.5 text-xs text-red-300">
                {t("blockchainConfig.disabled")}
              </span>
            )}
          </h4>

          {!disableMainnet ? (
            <div className="space-y-6">
              <div>
                <h5 className="mb-3 flex items-center text-sm font-bold text-blue-300">
                  <Layers className="mr-2 h-4 w-4" />
                  {t("blockchainConfig.layer1Networks")}
                </h5>
                <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
                  {mainnetL1.map(chain => (
                    <ChainCheckbox key={chain.id} chain={chain} />
                  ))}
                </div>
              </div>
              <div>
                <h5 className="mb-3 flex items-center text-sm font-bold text-green-300">
                  <Puzzle className="mr-2 h-4 w-4" />
                  {t("blockchainConfig.layer2Networks")}
                </h5>
                <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
                  {mainnetL2.map(chain => (
                    <ChainCheckbox key={chain.id} chain={chain} />
                  ))}
                </div>
              </div>
            </div>
          ) : (
            <div className="rounded-lg bg-(--bg-surface-secondary) py-4 text-center text-sm text-(--fg-secondary)">
              {t("blockchainConfig.mainnetDisabled")}
            </div>
          )}
        </div>

        <div
          className={`mb-6 space-y-4 transition-all duration-300 ${
            disableTestnet ? "pointer-events-none opacity-50" : ""
          }`}
        >
          <h4 className="flex items-center text-sm font-semibold text-orange-300">
            <FlaskConical className="mr-2 h-4 w-4" />
            {t("blockchainConfig.testnetNetworks")}
            {disableTestnet && (
              <span className="ml-2 rounded bg-red-500/20 px-2 py-0.5 text-xs text-red-300">
                {t("blockchainConfig.disabled")}
              </span>
            )}
          </h4>

          {!disableTestnet ? (
            <div className="space-y-6">
              {testnetL1.length > 0 && (
                <div>
                  <h5 className="mb-3 flex items-center text-sm font-bold text-blue-300">
                    <Layers className="mr-2 h-4 w-4" />
                    {t("blockchainConfig.layer1Networks")}
                  </h5>
                  <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
                    {testnetL1.map(chain => (
                      <ChainCheckbox key={chain.id} chain={chain} />
                    ))}
                  </div>
                </div>
              )}
              {testnetL2.length > 0 && (
                <div>
                  <h5 className="mb-3 flex items-center text-sm font-bold text-green-300">
                    <Puzzle className="mr-2 h-4 w-4" />
                    {t("blockchainConfig.layer2Networks")}
                  </h5>
                  <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
                    {testnetL2.map(chain => (
                      <ChainCheckbox key={chain.id} chain={chain} />
                    ))}
                  </div>
                </div>
              )}
            </div>
          ) : (
            <div className="rounded-lg bg-(--bg-surface-secondary) py-4 text-center text-sm text-(--fg-secondary)">
              {t("blockchainConfig.testnetDisabled")}
            </div>
          )}
        </div>

        <div className="border-t border-(--line-subtle) pt-4">
          {chainIds.length === 0 ? (
            <div className="py-2 text-center text-xs text-(--fg-secondary)">
              {t("blockchainConfig.usingAllChainsMode")}
            </div>
          ) : (
            <div className="text-xs text-(--fg-secondary)">
              {t("blockchainConfig.selectedChains", {
                count: chainIds.length,
                plural: chainIds.length === 1 ? "" : "s",
                mainnetCount:
                  mainnetL1.filter(c => chainIds.includes(c.id)).length +
                  mainnetL2.filter(c => chainIds.includes(c.id)).length,
                testnetCount:
                  testnetL1.filter(c => chainIds.includes(c.id)).length +
                  testnetL2.filter(c => chainIds.includes(c.id)).length,
              })}
            </div>
          )}
        </div>
      </div>

      {toast && (
        <div className="fixed bottom-5 left-1/2 z-100 -translate-x-1/2 rounded-full border border-(--line-brand) bg-(--bg-surface-primary) px-5 py-2.5 text-sm font-medium text-(--fg-primary) shadow-xl">
          {toast}
        </div>
      )}
    </PageShell>
  );
}
